import{_ as a,o as t,c as n,a2 as s}from"./chunks/framework.B72_uj9U.js";const g=JSON.parse('{"title":"ForgeCode","description":"","frontmatter":{"title":"ForgeCode","category":"agents"},"headers":[],"relativePath":"research/agents/forgecode/index.md","filePath":"research/agents/forgecode/index.md"}'),r={name:"research/agents/forgecode/index.md"};function o(i,e,l,c,p,d){return t(),n("div",null,[...e[0]||(e[0]=[s(`<h1 id="forgecode" tabindex="-1">ForgeCode <a class="header-anchor" href="#forgecode" aria-label="Permalink to &quot;ForgeCode&quot;">​</a></h1><blockquote><p>ZSH-native terminal coding agent; #1 on Terminal-Bench 2.0 (81.8% with both Claude Opus 4.6 and GPT-5.4).</p></blockquote><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>ForgeCode is a terminal-first AI coding agent built by <a href="https://github.com/antinomyhq" target="_blank" rel="noreferrer">Antinomy HQ</a>. The open-source core lives at <a href="https://github.com/antinomyhq/forge" target="_blank" rel="noreferrer">github.com/antinomyhq/forge</a>, written in Rust. A proprietary runtime layer called <strong>ForgeCode Services</strong> adds a context engine, tool-call corrections, and skill routing on top.</p><p>What makes ForgeCode architecturally distinct from other terminal agents (Claude Code, Aider, etc.) is the combination of:</p><ol><li><strong>Multi-agent architecture</strong> — three specialized sub-agents (Forge, Muse, Sage) with different access levels and purposes, rather than a single monolithic loop.</li><li><strong>ZSH-native integration</strong> — the <code>:</code> sentinel character lets users send prompts from their native shell without entering a separate REPL. Aliases, Oh My Zsh plugins, and custom functions keep working.</li><li><strong>Model routing</strong> — users can assign different models to different task phases (thinking model for planning, fast model for execution, large-context model for big files) and switch mid-session.</li><li><strong>ForgeCode Services</strong> — a proprietary runtime layer providing semantic entry-point discovery, dynamic skill loading, tool-call correction, todo enforcement, and progressive reasoning budget control.</li></ol><h2 id="sub-agents" tabindex="-1">Sub-Agents <a class="header-anchor" href="#sub-agents" aria-label="Permalink to &quot;Sub-Agents&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Agent</th><th>Access</th><th>Purpose</th></tr></thead><tbody><tr><td><strong>Forge</strong></td><td>Read + Write</td><td>Implementation — modifies files, creates code, executes commands. Active by default.</td></tr><tr><td><strong>Muse</strong></td><td>Read-only</td><td>Planning &amp; analysis — creates detailed plans, reviews impact, analyzes architecture.</td></tr><tr><td><strong>Sage</strong></td><td>Read-only</td><td>Research &amp; investigation — traces bugs, maps dependencies, understands codebases. Used internally by Forge and Muse.</td></tr></tbody></table><p><strong>Typical workflow</strong>: Muse plans → Forge implements. Both delegate research to Sage transparently.</p><h2 id="key-differentiators" tabindex="-1">Key Differentiators <a class="header-anchor" href="#key-differentiators" aria-label="Permalink to &quot;Key Differentiators&quot;">​</a></h2><ul><li><strong>ZSH-native</strong>: Type <code>:</code> + space + prompt. No environment switch. File tagging with <code>@</code> + Tab.</li><li><strong>Multi-agent, not single loop</strong>: Each agent operates on bounded, minimal context for its role.</li><li><strong>ForgeCode Services context engine</strong>: Semantic search, entry-point discovery, up to 93% fewer tokens than naive approaches.</li><li><strong>Tool corrections</strong>: Heuristic + static analysis layer auto-corrects tool-call arguments before dispatch — critical for local/open-weight models.</li><li><strong>Progressive thinking policy</strong>: High reasoning budget for first 10 messages (planning), low for execution, high again at verification checkpoints.</li><li><strong>Enforced verification skill</strong>: Before completing a task, the runtime programmatically requires a reviewer-mode pass — &quot;what evidence proves this is actually done?&quot;</li></ul><h2 id="benchmark-results-terminal-bench-2-0" tabindex="-1">Benchmark Results (Terminal-Bench 2.0) <a class="header-anchor" href="#benchmark-results-terminal-bench-2-0" aria-label="Permalink to &quot;Benchmark Results (Terminal-Bench 2.0)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Model</th><th>Score</th><th>Rank</th></tr></thead><tbody><tr><td>Claude Opus 4.6</td><td>81.8%</td><td>#1</td></tr><tr><td>GPT 5.4</td><td>81.8%</td><td>#1 (tied)</td></tr><tr><td>Gemini 3.1 Pro Preview</td><td>78.4%</td><td>(previous SOTA)</td></tr></tbody></table><p>For comparison, Google reports Gemini 3.1 Pro at 68.5% on TermBench running natively. ForgeCode&#39;s runtime harness added ~10 percentage points on the same model weights.</p><h2 id="architecture-at-a-glance" tabindex="-1">Architecture at a Glance <a class="header-anchor" href="#architecture-at-a-glance" aria-label="Permalink to &quot;Architecture at a Glance&quot;">​</a></h2><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  ZSH Shell (native)                         │</span></span>
<span class="line"><span>│  \`:\` sentinel → ForgeCode Plugin            │</span></span>
<span class="line"><span>└──────────────┬──────────────────────────────┘</span></span>
<span class="line"><span>               │</span></span>
<span class="line"><span>┌──────────────▼──────────────────────────────┐</span></span>
<span class="line"><span>│  ForgeCode Runtime                          │</span></span>
<span class="line"><span>│  ┌─────────┐ ┌─────────┐ ┌─────────┐       │</span></span>
<span class="line"><span>│  │  FORGE  │ │  MUSE   │ │  SAGE   │       │</span></span>
<span class="line"><span>│  │ (impl)  │ │ (plan)  │ │(research)│      │</span></span>
<span class="line"><span>│  └────┬────┘ └────┬────┘ └────┬────┘       │</span></span>
<span class="line"><span>│       └───────────┼───────────┘             │</span></span>
<span class="line"><span>│                   │                         │</span></span>
<span class="line"><span>│  ┌────────────────▼────────────────────┐    │</span></span>
<span class="line"><span>│  │  ForgeCode Services (proprietary)   │    │</span></span>
<span class="line"><span>│  │  • Context engine (semantic search) │    │</span></span>
<span class="line"><span>│  │  • Tool-call correction layer       │    │</span></span>
<span class="line"><span>│  │  • Skill engine (dynamic loading)   │    │</span></span>
<span class="line"><span>│  │  • Todo enforcement                 │    │</span></span>
<span class="line"><span>│  │  • Progressive thinking policy      │    │</span></span>
<span class="line"><span>│  └────────────────┬────────────────────┘    │</span></span>
<span class="line"><span>│                   │                         │</span></span>
<span class="line"><span>│  ┌────────────────▼────────────────────┐    │</span></span>
<span class="line"><span>│  │  LLM Providers                      │    │</span></span>
<span class="line"><span>│  │  Anthropic · OpenAI · Google ·      │    │</span></span>
<span class="line"><span>│  │  DeepSeek · Mistral · Meta · etc.   │    │</span></span>
<span class="line"><span>│  └─────────────────────────────────────┘    │</span></span>
<span class="line"><span>└─────────────────────────────────────────────┘</span></span></code></pre></div><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#89B4FA;font-style:italic;">curl</span><span style="color:#A6E3A1;"> -fsSL</span><span style="color:#A6E3A1;"> https://forgecode.dev/cli</span><span style="color:#94E2D5;"> |</span><span style="color:#89B4FA;font-style:italic;"> sh</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">forge</span><span style="color:#A6E3A1;"> setup</span><span style="color:#6C7086;font-style:italic;">    # configure ZSH plugin</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">forge</span><span style="color:#A6E3A1;"> login</span><span style="color:#6C7086;font-style:italic;">    # authenticate with an AI provider</span></span>
<span class="line"><span style="color:#F38BA8;font-style:italic;">:</span><span style="color:#A6E3A1;"> hello</span><span style="color:#A6E3A1;"> world</span><span style="color:#6C7086;font-style:italic;">  # first prompt from native shell</span></span></code></pre></div><p>Works on macOS, Linux, Android, and Windows (WSL/Git Bash). Requires ZSH and a Nerd Font.</p><h2 id="open-source-vs-proprietary" tabindex="-1">Open Source vs. Proprietary <a class="header-anchor" href="#open-source-vs-proprietary" aria-label="Permalink to &quot;Open Source vs. Proprietary&quot;">​</a></h2><ul><li><strong>Open source</strong> (<a href="https://github.com/antinomyhq/forge" target="_blank" rel="noreferrer">github.com/antinomyhq/forge</a>): Core agent, multi-agent framework, tool definitions, ZSH plugin, all configuration.</li><li><strong>Proprietary</strong> (ForgeCode Services): Context engine, tool-call correction layer, skill routing, semantic search indexing, todo enforcement, reasoning budget control. Currently free to use.</li></ul><h2 id="deep-dive-files" tabindex="-1">Deep-Dive Files <a class="header-anchor" href="#deep-dive-files" aria-label="Permalink to &quot;Deep-Dive Files&quot;">​</a></h2><table tabindex="0"><thead><tr><th>File</th><th>Topic</th></tr></thead><tbody><tr><td><a href="./architecture.html">architecture.md</a></td><td>Multi-agent architecture — Forge, Muse, Sage, bounded context</td></tr><tr><td><a href="./agentic-loop.html">agentic-loop.md</a></td><td>How the multi-agent loop orchestrates tasks</td></tr><tr><td><a href="./tool-system.html">tool-system.md</a></td><td>Tool system, tool corrections for local models</td></tr><tr><td><a href="./context-management.html">context-management.md</a></td><td>Context engine, bounded context across sub-agents</td></tr><tr><td><a href="./unique-patterns.html">unique-patterns.md</a></td><td>Key differentiators and novel patterns</td></tr><tr><td><a href="./benchmarks.html">benchmarks.md</a></td><td>Terminal-Bench 2.0 scores and analysis</td></tr><tr><td><a href="./references.html">references.md</a></td><td>All source links</td></tr></tbody></table><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li>Website: <a href="https://forgecode.dev" target="_blank" rel="noreferrer">https://forgecode.dev</a></li><li>Docs: <a href="https://forgecode.dev/docs" target="_blank" rel="noreferrer">https://forgecode.dev/docs</a></li><li>GitHub: <a href="https://github.com/antinomyhq/forge" target="_blank" rel="noreferrer">https://github.com/antinomyhq/forge</a></li><li>Blog (Part 1): <a href="https://forgecode.dev/blog/benchmarks-dont-matter/" target="_blank" rel="noreferrer">https://forgecode.dev/blog/benchmarks-dont-matter/</a></li><li>Blog (Part 2): <a href="https://forgecode.dev/blog/gpt-5-4-agent-improvements/" target="_blank" rel="noreferrer">https://forgecode.dev/blog/gpt-5-4-agent-improvements/</a></li><li>Terminal-Bench 2.0 leaderboard: <a href="https://www.tbench.ai/leaderboard/terminal-bench/2.0" target="_blank" rel="noreferrer">https://www.tbench.ai/leaderboard/terminal-bench/2.0</a></li></ul>`,25)])])}const u=a(r,[["render",o]]);export{g as __pageData,u as default};
